class User:
    def __init__(self, name, email, age):
        self.name = name
        self.email = email
        self.age = age

    def adult(self):
        return self.age >= 18

    def __str__(self):
        return f"User({self.name}, {self.email}, age={self.age})"

    @classmethod
    def create(cls, name, email, age):
        return cls(name, email, age)

